const LOGO_BASE64 = ""

const headers = {
  "Access-Control-Allow-Origin": "*",
  "Cache-Control": "public, max-age=31536000, immutable",
}

function decodeBase64Png(base64: string): Uint8Array {
  const binary = atob(base64)
  const bytes = new Uint8Array(binary.length)
  for (let index = 0; index < binary.length; index += 1) {
    bytes[index] = binary.charCodeAt(index)
  }
  return bytes
}

Deno.serve((req: Request) => {
  const url = new URL(req.url)

  if (req.method === "OPTIONS") {
    return new Response(null, {
      headers: {
        ...headers,
        "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
        "Access-Control-Allow-Methods": "GET, OPTIONS",
      },
    })
  }

  if (req.method !== "GET") {
    return new Response("Method not allowed", { status: 405 })
  }

  if (url.pathname.endsWith("/logo.png")) {
    const logo = decodeBase64Png(LOGO_BASE64)
    return new Response(logo, {
      headers: {
        ...headers,
        "Content-Type": "image/png",
        "Content-Length": String(logo.byteLength),
      },
    })
  }

  return new Response("Profitness email assets", {
    headers: {
      ...headers,
      "Content-Type": "text/plain; charset=utf-8",
    },
  })
})
